# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
from requests.auth import HTTPBasicAuth

# Configuration
RABBITMQ_HOST = 'http://localhost:15672'
ADMIN_USER = 'admin'
ADMIN_PASSWORD = 'password'

def create_vhost(vhost_name):
    url = f"{RABBITMQ_HOST}/api/vhosts/{vhost_name}"
    response = requests.put(url, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD))
    if response.status_code == 201:
        print(f"Vhost '{vhost_name}' created successfully.")
    else:
        print(f"Failed to create vhost '{vhost_name}'. Status code: {response.status_code}")

def set_permissions(user, vhost, configure='.*', write='.*', read='.*'):
    url = f"{RABBITMQ_HOST}/api/permissions/{vhost}/{user}"
    data = {
        'configure': configure,
        'write': write,
        'read': read
    }
    response = requests.put(url, json=data, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD))
    if response.status_code == 201:
        print(f"Permissions set for user '{user}' on vhost '{vhost}'.")
    else:
        print(f"Failed to set permissions for user '{user}' on vhost '{vhost}'. Status code: {response.status_code}")

def create_user(user, password):
    url = f"{RABBITMQ_HOST}/api/users/{user}"
    data = {
        'password': password,
        'tags': ''
    }
    response = requests.put(url, json=data, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD))
    if response.status_code == 201:
        print(f"User '{user}' created successfully.")
    else:
        print(f"Failed to create user '{user}'. Status code: {response.status_code}")

# Example usage
create_vhost('app1_vhost')
create_user('app1_user', 'app1_password')
set_permissions('app1_user', 'app1_vhost')

create_vhost('app2_vhost')
create_user('app2_user', 'app2_password')
set_permissions('app2_user', 'app2_vhost')